insert into order_timeout_outbox (
    order_id, message_id, payload, expire_time, status, retry_count, next_retry_time,
    publish_claim_time, sent_time, last_error, create_time, update_time
)
values (
    #{orderId}, #{messageId}, #{payload}, #{expireTime}, #{status}, #{retryCount}, #{nextRetryTime},
    #{publishClaimTime}, #{sentTime}, #{lastError}, #{createTime}, #{updateTime}
)

mapper.select:
select 
from order_timeout_outbox
where status in (#{pendingStatus}, #{failedStatus})
  and next_retry_time <= #{now}
  and retry_count < #{maxRetryCount}
order by next_retry_time asc, id asc
limit #{limit}

mapper.update:
update order_timeout_outbox
set status = #{publishingStatus},
    publish_claim_time = #{now},
    update_time = #{now}
where id = #{id}
  and status in (#{pendingStatus}, #{failedStatus})
  and next_retry_time <= #{now}
  and retry_count < #{maxRetryCount}

update order_timeout_outbox
set status = #{sentStatus},
    sent_time = #{now},
    last_error = null,
    update_time = #{now}
where id = #{id}
  and status = #{publishingStatus}

update order_timeout_outbox
set status = #{failedStatus},
    retry_count = retry_count + 1,
    next_retry_time = #{nextRetryTime},
    last_error = #{lastError},
    update_time = #{now}
where id = #{id}
  and status = #{publishingStatus}

update order_timeout_outbox
set status = #{failedStatus},
    retry_count = retry_count + 1,
    next_retry_time = #{nextRetryTime},
    last_error = #{lastError},
    update_time = #{now}
where status = #{publishingStatus}
  and publish_claim_time <= #{claimDeadline}
  and retry_count < #{maxRetryCount}
